var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"허억……! 허억……! 허억……!","JPN":"はあ……！　はあ……！　はあ……！","ENG":"*Huff…!* *Huff…!* *Huff…!*","TWN":"呼呼……！呼呼……！呼呼……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"수고했어, 중사. 사격 솜씨가 대단하더라.","JPN":"お疲れ、軍曹。すばらしい射撃だったよ。","ENG":"Good work, Sergeant. Amazing gunnery skills you have.","TWN":"中士，辛苦啦！你的射擊技巧很厲害呢！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"레버넌트 씨…….","JPN":"レヴナントさん……","ENG":"Revenant...","TWN":"亡靈小姐……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"어차피 이제 다 아실 테니까, 그…….","JPN":"もう全部おわかりでしょうから、その……","ENG":"You can probably tell by now, so...","TWN":"反正你都已經知道了，我……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그래도 놀랐어. 정부군은 요즘 이터니움 탄을 보급해 주기도 하나 보네.","JPN":"でもビックリした。最近の政府軍はエタニウム弾を補給してくれたりするんだね。","ENG":"I’m surprised. I didn’t know the government forces were being supplied with Eternium bullets these days.","TWN":"不過真是意外呢！政府軍最近還有配給永恆之金子彈喔？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"네……?","JPN":"はい……？","ENG":"What...?","TWN":"蛤……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"아, 혹시 제식 무기가 아니라 그런가? 2종 침식체 상대로도 어느 정도 유효하던걸.","JPN":"あ、もしかして所定の武器じゃないからかな？　第2種侵食体を相手に、ある程度有効だったし。","ENG":"Ah, maybe it’s because it’s not standard equipment? It seems kind of effective against a Category 2 C.O..","TWN":"是因為不是制式武器嗎？對付2類侵蝕體好像也滿有效的？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……아, 하하. 네. 그렇죠, 뭐. 수훈자의 특권이라고나 할까요.","JPN":"……あ、はは。まあ。そうですね、はい。受勲者の特権ってところです。","ENG":"Oh... Ha ha... Yes, That’s right. Well, that’s a special privilege for awarded soldiers like me.","TWN":"……喔～哈哈哈，對啊，算是授勳者的特權吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"다행이야. 여차하면 건물째로 날려 버리려고 했거든.","JPN":"よかった。いざとなれば建物ごと爆破しようと思ってたから。","ENG":"I’m glad. I had been planning on blowing up the whole building.","TWN":"那就好～我本來還想說，萬一真的不行要毀掉整棟建築的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그나저나…….","JPN":"それより……","ENG":"Ah, on another note...","TWN":"不過……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그 침식체, 묘한 걸 가지고 있었네.","JPN":"あの侵食体、妙なのを持ってたのね。","ENG":"That Corrupted Object had something interesting.","TWN":"那個侵蝕體身上好像有奇怪的東西？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"이 메모는 암보를 하느라 적었던 모양인데……. 이 곡, 설마…….","JPN":"このメモは暗譜のために書いたみたいだけど……この曲、まさか……","ENG":"It looks like someone tried to memorize a musical score... Wait, this song, no way...","TWN":"這張紙上面寫的是樂譜吧……這首曲子，難道是……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그게 침식체한테서 떨어졌다고요? 악보 아니에요?","JPN":"それを侵食体が落としたんですか？　楽譜じゃないですか？","ENG":"That fell off the Corrupted Object? Isn’t that a musical score?","TWN":"這是從侵蝕體身上掉下來的？這不是樂譜嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……응. 맞아. 그것도 오케스트라 총보야.","JPN":"……うん。そう。それもフルスコア。","ENG":"...Yes, that’s right. It’s a full score for an orchestra.","TWN":"……沒錯，而且還是管弦樂團的總譜。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"총보? 그냥 악보랑 뭔가 다른 건가요?","JPN":"フルスコア？　ただの楽譜と何が違うんですか？","ENG":"A full score? What distinguishes full scores from regular scores?","TWN":"總譜？跟一般的樂譜不一樣嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"간단히 말하면 연주에 쓰는 모든 악기의 악보를 합쳐 놓은 거야.","JPN":"簡単に言うと、演奏に使われるすべての楽器の楽譜をまとめたものよ。","ENG":"Simply put, a full score is a collection of all the musical scores for every instrument in the orchestra.","TWN":"簡單地說，就是樂團裡所有樂器的樂譜都在上面。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그리고 이런 악보가 꼭 필요한 사람이 한 명 있어.","JPN":"そしてこんな楽譜が必要な人はたった一人だけ。","ENG":"There’s only one person that needs something like this.","TWN":"而只有一種人會需要總譜。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"모든 악기의 악보라면…….","JPN":"すべての楽器の楽譜なら……","ENG":"A collection of all the music scores for every instrument...","TWN":"所有樂器的樂譜……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"지휘자……?","JPN":"指揮者……？","ENG":"The conductor...?","TWN":"指揮家……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"맞아.","JPN":"そのとおり。","ENG":"Correct.","TWN":"正確！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"무슨 일이 있었는지는 더 알아 봐야겠지만……. 결국 한 발 늦은 모양이야.","JPN":"何があったのかはもっと調べてみないとわからないけど……結局手遅れだったようね。","ENG":"We need to look into this further but... In the end, it looks like we fell a step behind.","TWN":"必須再調查一下到底發生什麼事……看來我們來晚了一步。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};